const matches = $input.first().json.matches || [];
function titleCase(str) {
  return (str || "").split(" ")
    .map(w => w.charAt(0).toUpperCase() + w.slice(1))
    .join(" ");
}
function getIndustry(org, enriched) {
  const raw = org.industry || enriched.industry || "";
  const kws = org.keywords || enriched.keywords || [];
  const firstKw = kws[0] || "";
  let label = "";
  if (raw && firstKw) {
    label = firstKw.length < raw.length ? firstKw : raw;
  } else {
    label = raw || firstKw;
  }
  return titleCase(label);
}
const outputItems = [];
for (const enriched of matches) {
  const org = enriched.organization || {};
  const full_name =
    `${enriched.first_name || ""} ${enriched.last_name_unobfuscated || enriched.last_name || ""}`.trim() ||
    enriched.name ||
    "";
  const rawTitle = enriched.title || "";
  const job_title = [...new Set(rawTitle.split(",").map(t => t.trim()))][0] || "";
  let phone = "";
  const phoneNumbers = enriched.phone_numbers || [];
  if (phoneNumbers.length) {
    const preferred = phoneNumbers.find(p =>
      ["work", "direct", "work_hq"].includes(p.type)
    );
    phone = preferred?.sanitized_number || phoneNumbers[0]?.sanitized_number || "";
  }
  if (!phone) {
    phone = org.phone || org.primary_phone?.number || "";
  }
  if (phone && !phone.startsWith("*")) {
    phone = "'" + phone;
  } else {
    phone = "";
  }
  let linkedin = enriched.linkedin_url || "";
  if (linkedin && !linkedin.startsWith("http")) {
    linkedin = "https://linkedin.com" + linkedin;
  }
  const record = {
    "Apollo ID":       enriched.id || "",
    "Full Name":       full_name,
    "Job Title":       job_title,
    "Company":         org.name || "",
    "Email Address":   enriched.email || "",
    "Phone Number":    phone,
    "Profile URL":     linkedin,
    "Company Website": org.website_url || "",
    "Industry Genre":  getIndustry(org, enriched),
  };
  for (const key of Object.keys(record)) {
    if (!record[key]) record[key] = "";
  }
  outputItems.push({ json: record });
}
return outputItems;

const people = $input.first().json.people || [];
const jobTitle = $('Lead Generation Form').first().json['Job Title'] || '';

return people.map(person => {
  return {
    json: {
      id: person.id,
      person: person,
      designation: jobTitle
    }
  };
});

const allItems = $input.all();

const newId = allItems[0].json.id;
const person = allItems[0].json.person;
const name = person.name || `${person.first_name || ''} ${person.last_name || ''}`.trim();
const designation = allItems[0].json.designation || '';

const sheetRows = allItems.slice(1);
const existingIds = sheetRows.map(i => i.json['Apollo ID']).filter(Boolean);

const isDuplicate = existingIds.includes(newId);

return [{ json: { 
  id: newId,
  name: name,
  designation: designation,
  isDuplicate: isDuplicate 
} }];

